mapper.select:
select lend.id, lend.user_id, lend.book_id, lend.create_time as lend_time, lend.due_time, lend.return_time, lend.renew_count, lend.state, user.username, book.book_name from tb_lend lend join tb_user user on lend.user_id = user.id join tb_book book on lend.book_id = book.id where lend.is_delete = 0
and lend.user_id = #{lendPageDTO.userId}
and lend.book_id = #{lendPageDTO.bookId}
and lend.state = #{lendPageDTO.state}

select book.id, book.book_name, book.cover_url, author.author_name, publisher.publisher_name, book.isbn, lend.create_time as lendTime, lend.due_time as dueTime from tb_lend lend join tb_book book on lend.book_id = book.id join tb_author author on book.author_id = author.id join tb_publisher publisher on book.publisher_id = publisher.id where lend.is_delete = 0 and lend.user_id = #{myLendPageDTO.userId} and (lend.state=1 or lend.state=3)
and ( book.book_name like concat('%', #{myLendPageDTO.keyword}, '%') or author.author_name like concat('%', #{myLendPageDTO.keyword}, '%') or publisher.publisher_name like concat('%', #{myLendPageDTO.keyword}, '%') or book.isbn like concat('%', #{myLendPageDTO.keyword}, '%') )
and lend.create_time >= #{myLendPageDTO.startDate}
and lend.create_time <= #{myLendPageDTO.endDate}
order by lend.create_time desc

select book.id, book.book_name, author.author_name, publisher.publisher_name, book.isbn, lend.state, book.cover_url, lend.create_time as lendTime, lend.return_time as returnTime from tb_lend lend join tb_book book on lend.book_id = book.id join tb_author author on book.author_id = author.id join tb_publisher publisher on book.publisher_id = publisher.id where lend.is_delete = 0 and lend.user_id = #{myLendPageDTO.userId}
and ( book.book_name like concat('%', #{myLendPageDTO.keyword}, '%') or author.author_name like concat('%', #{myLendPageDTO.keyword}, '%') or publisher.publisher_name like concat('%', #{myLendPageDTO.keyword}, '%') or book.isbn like concat('%', #{myLendPageDTO.keyword}, '%') )
and lend.create_time >= #{myLendPageDTO.startDate}
and lend.create_time <= #{myLendPageDTO.endDate}
order by lend.create_time desc
